import{animate,inView}from "motion";(function(){function parseCounterValue(text){var raw=text.trim();var suffix="";var multiplier=1;var decimals=0;if(raw.endsWith("%")){suffix="%";raw=raw.slice(0,-1)}else if(/[Kk]$/.test(raw)){suffix="K";raw=raw.slice(0,-1);multiplier=1000}else if(/[Mm]$/.test(raw)){suffix="M";raw=raw.slice(0,-1);multiplier=1000000}else if(raw.endsWith("+")){suffix="+";raw=raw.slice(0,-1)}var hasCommas=/,/.test(raw);raw=raw.replace(/,/g,"");if(raw.includes("."))decimals=raw.split(".")[1].length;var num=parseFloat(raw);if(isNaN(num))return null;return{target:num*multiplier,suffix:suffix,decimals:decimals,hasCommas:hasCommas}}function formatCounterValue(value,info){var display;var effective=info.suffix==="K"?value/1000:info.suffix==="M"?value/1000000:value;if(info.decimals>0)display=effective.toFixed(info.decimals);else display=Math.round(effective).toString();if(info.hasCommas){var parts=display.split(".");parts[0]=parts[0].replace(/\B(?=(\d{3})+(?!\d))/g,",");display=parts.join(".")}if(info.suffix)display+=info.suffix;return display}document.addEventListener("DOMContentLoaded",function(){var animOptions={duration:0.7,easing:[0.17,0.55,0.55,1]};var scaleOptions={duration:0.6,easing:[0.17,0.55,0.55,1]};document.querySelectorAll(".motion-reveal,.motion-reveal-left,.motion-reveal-right,.motion-reveal-scale").forEach(function(el){var keyframes,options;if(el.classList.contains("motion-reveal-left")){keyframes={opacity:[0,1],x:[-40,0]};options=animOptions}else if(el.classList.contains("motion-reveal-right")){keyframes={opacity:[0,1],x:[40,0]};options=animOptions}else if(el.classList.contains("motion-reveal-scale")){keyframes={opacity:[0,1],scale:[0.95,1]};options=scaleOptions}else{keyframes={opacity:[0,1],y:[40,0]};options=animOptions}inView(el,function(){return animate(el,keyframes,options)},{amount:0.2,once:true})});var counters=document.querySelectorAll("[data-counter]");if(counters.length){counters.forEach(function(el){var originalText=el.textContent.trim();var info=parseCounterValue(originalText);if(!info)return;el.textContent="0";inView(el,function(){animate(0,info.target,{duration:2,ease:"circOut",onUpdate:function(latest){el.textContent=formatCounterValue(latest,info)}})},{amount:0.5,once:true})})}})})();